import{_ as t,o,c as a,ae as l}from"./chunks/framework.BEtfQoF7.js";const p=JSON.parse('{"title":"웹에서 Claude Code 시작하기","description":"브라우저나 휴대폰에서 클라우드로 Claude Code를 실행하세요. GitHub 저장소를 연결하고 작업을 제출한 뒤, 로컬 설정 없이 PR을 검토할 수 있습니다.","frontmatter":{"title":"웹에서 Claude Code 시작하기","description":"브라우저나 휴대폰에서 클라우드로 Claude Code를 실행하세요. GitHub 저장소를 연결하고 작업을 제출한 뒤, 로컬 설정 없이 PR을 검토할 수 있습니다."},"headers":[],"relativePath":"web-quickstart.md","filePath":"web-quickstart.md","lastUpdated":1776205703000}'),d={name:"web-quickstart.md"};function r(n,e,s,i,c,u){return o(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="웹에서-claude-code-시작하기" tabindex="-1">웹에서 Claude Code 시작하기 <a class="header-anchor" href="#웹에서-claude-code-시작하기" aria-label="Permalink to &quot;웹에서 Claude Code 시작하기&quot;">​</a></h1><blockquote><p>브라우저나 휴대폰에서 클라우드로 Claude Code를 실행하세요. GitHub 저장소를 연결하고 작업을 제출한 뒤, 로컬 설정 없이 PR을 검토할 수 있습니다.</p></blockquote><div class="info custom-block"><p class="custom-block-title">INFO</p><p>웹에서의 Claude Code는 Pro, Max, Team 사용자와 프리미엄 시트 또는 Chat + Claude Code 시트를 보유한 Enterprise 사용자를 대상으로 리서치 프리뷰 중입니다.</p></div><p>웹에서의 Claude Code는 사용자 머신이 아닌 Anthropic이 관리하는 클라우드 인프라에서 실행됩니다. 브라우저의 <a href="https://claude.ai/code" target="_blank" rel="noreferrer">claude.ai/code</a> 또는 Claude 모바일 앱에서 작업을 제출하세요.</p><p>시작하려면 GitHub 저장소가 필요합니다. Claude는 이를 격리된 가상 머신에 클론하고, 변경 사항을 만들어 검토할 브랜치를 푸시합니다. 세션은 기기 간에 유지되므로, 노트북에서 시작한 작업을 나중에 휴대폰에서 검토할 수 있습니다.</p><p>웹에서의 Claude Code는 다음 상황에 적합합니다:</p><ul><li><strong>병렬 작업</strong>: 여러 독립적인 작업을 동시에 실행하되, 각각 별도의 세션과 브랜치에서 worktree 관리 없이 진행</li><li><strong>로컬에 없는 저장소</strong>: Claude가 매 세션마다 저장소를 새로 클론하므로, 로컬에 체크아웃할 필요 없음</li><li><strong>자주 방향을 조정하지 않아도 되는 작업</strong>: 명확하게 정의된 작업을 제출하고, 다른 일을 하다가 Claude가 완료되면 결과 검토</li><li><strong>코드 질문 및 탐색</strong>: 로컬 체크아웃 없이 코드베이스를 이해하거나 기능이 어떻게 구현되었는지 추적</li></ul><p>로컬 설정, 도구, 환경이 필요한 작업에는 Claude Code를 로컬에서 실행하거나 <a href="/claude-code-docs-ko/remote-control.html">Remote Control</a>을 사용하는 것이 더 적합합니다.</p><h2 id="세션-실행-방식" tabindex="-1">세션 실행 방식 <a class="header-anchor" href="#세션-실행-방식" aria-label="Permalink to &quot;세션 실행 방식&quot;">​</a></h2><p>작업을 제출하면:</p><ol><li><strong>클론 및 준비</strong>: 저장소가 Anthropic 관리 VM에 클론되고, 설정된 경우 <a href="/claude-code-docs-ko/claude-code-on-the-web.html#setup-scripts">설정 스크립트</a>가 실행됩니다.</li><li><strong>네트워크 구성</strong>: 환경의 <a href="/claude-code-docs-ko/claude-code-on-the-web.html#access-levels">액세스 수준</a>에 따라 인터넷 접근이 설정됩니다.</li><li><strong>작업 진행</strong>: Claude가 코드를 분석하고, 변경 사항을 만들고, 테스트를 실행하며 결과를 확인합니다. 진행 상황을 직접 지켜보며 방향을 조정하거나, 완료될 때까지 자리를 비울 수도 있습니다.</li><li><strong>브랜치 푸시</strong>: Claude가 중단점에 도달하면 브랜치를 GitHub에 푸시합니다. diff를 검토하고, 인라인 댓글을 남기고, PR을 생성하거나, 메시지를 추가로 보내 계속 진행할 수 있습니다.</li></ol><p>브랜치가 푸시되어도 세션은 종료되지 않습니다. PR 생성 및 추가 수정은 모두 동일한 대화 내에서 이루어집니다.</p><h2 id="claude-code-실행-방식-비교" tabindex="-1">Claude Code 실행 방식 비교 <a class="header-anchor" href="#claude-code-실행-방식-비교" aria-label="Permalink to &quot;Claude Code 실행 방식 비교&quot;">​</a></h2><p>Claude Code는 어디서나 동일하게 동작합니다. 달라지는 것은 코드가 실행되는 위치와 로컬 설정의 사용 가능 여부입니다. Desktop 앱은 로컬 세션과 클라우드 세션 모두를 제공하므로, 아래 답변은 선택하는 유형에 따라 달라집니다:</p><table tabindex="0"><thead><tr><th style="text-align:left;"></th><th style="text-align:left;">웹</th><th style="text-align:left;">Remote Control</th><th style="text-align:left;">터미널 CLI</th><th style="text-align:left;">Desktop 앱</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>코드 실행 위치</strong></td><td style="text-align:left;">Anthropic 클라우드 VM</td><td style="text-align:left;">사용자 머신</td><td style="text-align:left;">사용자 머신</td><td style="text-align:left;">사용자 머신 또는 클라우드 VM</td></tr><tr><td style="text-align:left;"><strong>채팅 위치</strong></td><td style="text-align:left;">claude.ai 또는 모바일 앱</td><td style="text-align:left;">claude.ai 또는 모바일 앱</td><td style="text-align:left;">터미널</td><td style="text-align:left;">Desktop UI</td></tr><tr><td style="text-align:left;"><strong>로컬 설정 사용</strong></td><td style="text-align:left;">아니요, 저장소만</td><td style="text-align:left;">예</td><td style="text-align:left;">예</td><td style="text-align:left;">로컬은 예, 클라우드는 아니요</td></tr><tr><td style="text-align:left;"><strong>GitHub 필요</strong></td><td style="text-align:left;">예, 또는 <code>--remote</code>로 <a href="/claude-code-docs-ko/claude-code-on-the-web.html#send-local-repositories-without-github">로컬 저장소 번들링</a> 가능</td><td style="text-align:left;">아니요</td><td style="text-align:left;">아니요</td><td style="text-align:left;">클라우드 세션만 필요</td></tr><tr><td style="text-align:left;"><strong>연결 해제 후에도 계속 실행</strong></td><td style="text-align:left;">예</td><td style="text-align:left;">터미널이 열려 있는 동안</td><td style="text-align:left;">아니요</td><td style="text-align:left;">세션 유형에 따라 다름</td></tr><tr><td style="text-align:left;"><strong><a href="/claude-code-docs-ko/permission-modes.html">권한 모드</a></strong></td><td style="text-align:left;">편집 자동 수락, Plan</td><td style="text-align:left;">요청, 편집 자동 수락, Plan</td><td style="text-align:left;">전체 모드</td><td style="text-align:left;">세션 유형에 따라 다름</td></tr><tr><td style="text-align:left;"><strong>네트워크 접근</strong></td><td style="text-align:left;">환경별 설정 가능</td><td style="text-align:left;">사용자 머신 네트워크</td><td style="text-align:left;">사용자 머신 네트워크</td><td style="text-align:left;">세션 유형에 따라 다름</td></tr></tbody></table><p>터미널 설정은 <a href="/claude-code-docs-ko/quickstart.html">터미널 빠른 시작</a>, Desktop 앱은 <a href="/claude-code-docs-ko/desktop.html">Desktop</a>, Remote Control은 <a href="/claude-code-docs-ko/remote-control.html">Remote Control</a> 문서를 참조하세요.</p><h2 id="github-연결-및-환경-생성" tabindex="-1">GitHub 연결 및 환경 생성 <a class="header-anchor" href="#github-연결-및-환경-생성" aria-label="Permalink to &quot;GitHub 연결 및 환경 생성&quot;">​</a></h2><p>설정은 한 번만 하면 됩니다. 이미 GitHub CLI를 사용 중이라면 브라우저 대신 <a href="#connect-from-your-terminal">터미널에서 연결</a>할 수 있습니다.</p><p><strong>1단계: claude.ai/code 방문</strong></p><p><a href="https://claude.ai/code" target="_blank" rel="noreferrer">claude.ai/code</a>로 이동하여 Anthropic 계정으로 로그인하세요.</p><p><strong>2단계: Claude GitHub App 설치</strong></p><p>로그인 후, claude.ai/code에서 GitHub 연결을 안내합니다. 프롬프트를 따라 Claude GitHub App을 설치하고 저장소에 대한 접근 권한을 부여하세요. 클라우드 세션은 기존 GitHub 저장소에서 작동하므로, 새 프로젝트를 시작하려면 먼저 <a href="https://github.com/new" target="_blank" rel="noreferrer">GitHub에서 빈 저장소를 생성</a>하세요.</p><p><strong>3단계: 환경 생성</strong></p><p>GitHub 연결 후, 클라우드 환경 생성 안내가 표시됩니다. 환경은 세션 중 Claude의 네트워크 접근 권한과 새 세션 생성 시 실행할 내용을 제어합니다. 별도 설정 없이 사용 가능한 항목은 <a href="/claude-code-docs-ko/claude-code-on-the-web.html#installed-tools">설치된 도구</a>를 참조하세요.</p><p>양식에는 다음 필드가 있습니다:</p><ul><li><strong>Name</strong>: 표시용 레이블. 다양한 프로젝트나 액세스 수준에 대해 여러 환경이 있을 때 유용합니다.</li><li><strong>Network access</strong>: 세션이 인터넷에서 접근할 수 있는 범위를 제어합니다. 기본값인 <code>Trusted</code>는 npm, PyPI, RubyGems 등 <a href="/claude-code-docs-ko/claude-code-on-the-web.html#default-allowed-domains">일반적인 패키지 레지스트리</a>에 대한 연결을 허용하면서 일반 인터넷 접근은 차단합니다.</li><li><strong>Environment variables</strong>: 모든 세션에서 사용 가능한 선택적 변수로, <code>.env</code> 형식입니다. 값을 따옴표로 감싸지 마세요. 따옴표도 값의 일부로 저장됩니다. 이 환경을 편집할 수 있는 사람이라면 누구나 볼 수 있습니다.</li><li><strong>Setup script</strong>: 새 세션 생성 시 Claude Code가 실행되기 전에 실행되는 선택적 Bash 스크립트입니다. <code>apt install -y gh</code>와 같이 클라우드 VM에 포함되지 않은 시스템 도구를 설치하거나, 프로젝트에 필요한 서비스를 시작하는 데 사용합니다. 예시 및 디버깅 팁은 <a href="/claude-code-docs-ko/claude-code-on-the-web.html#setup-scripts">설정 스크립트</a>를 참조하세요.</li></ul><p>처음 프로젝트라면 기본값을 유지하고 <strong>Create environment</strong>를 클릭하세요. 이후 <a href="/claude-code-docs-ko/claude-code-on-the-web.html#configure-your-environment">환경을 편집하거나 추가 환경을 생성</a>할 수 있습니다.</p><h3 id="connect-from-your-terminal" tabindex="-1">터미널에서 연결 <a class="header-anchor" href="#connect-from-your-terminal" aria-label="Permalink to &quot;터미널에서 연결 {#connect-from-your-terminal}&quot;">​</a></h3><p>이미 GitHub CLI(<code>gh</code>)를 사용 중이라면 브라우저를 열지 않고 웹에서의 Claude Code를 설정할 수 있습니다. <a href="/claude-code-docs-ko/quickstart.html">Claude Code CLI</a>가 필요합니다. <code>/web-setup</code>은 로컬 <code>gh</code> 토큰을 읽어 Claude 계정과 연결하고, 환경이 없는 경우 기본 클라우드 환경을 생성합니다.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p><a href="/claude-code-docs-ko/zero-data-retention.html">Zero Data Retention</a>이 활성화된 조직은 <code>/web-setup</code> 또는 다른 클라우드 세션 기능을 사용할 수 없습니다. GitHub CLI가 설치되어 있지 않거나 인증되지 않은 경우, <code>/web-setup</code>은 브라우저 온보딩 흐름을 엽니다.</p></div><p><strong>1단계: GitHub CLI로 인증</strong></p><p>아직 인증하지 않았다면 셸에서 GitHub CLI를 인증하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span></span></code></pre></div><p><strong>2단계: Claude에 로그인</strong></p><p>Claude Code CLI에서 <code>/login</code>을 실행하여 claude.ai 계정으로 로그인하세요. 이미 로그인되어 있다면 이 단계를 건너뜁니다.</p><p><strong>3단계: /web-setup 실행</strong></p><p>Claude Code CLI에서 다음을 실행하세요:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/web-setup</span></span></code></pre></div><p>이 명령은 <code>gh</code> 토큰을 Claude 계정과 동기화합니다. 클라우드 환경이 없는 경우, <code>/web-setup</code>은 Trusted 네트워크 접근과 설정 스크립트 없이 환경을 생성합니다. 이후 <a href="/claude-code-docs-ko/claude-code-on-the-web.html#configure-your-environment">환경을 편집하거나 변수를 추가</a>할 수 있습니다. <code>/web-setup</code> 완료 후, <a href="/claude-code-docs-ko/claude-code-on-the-web.html#from-terminal-to-web"><code>--remote</code></a>로 터미널에서 클라우드 세션을 시작하거나 <a href="/claude-code-docs-ko/web-scheduled-tasks.html"><code>/schedule</code></a>로 반복 작업을 설정할 수 있습니다.</p><h2 id="작업-시작" tabindex="-1">작업 시작 <a class="header-anchor" href="#작업-시작" aria-label="Permalink to &quot;작업 시작&quot;">​</a></h2><p>GitHub가 연결되고 환경이 생성되면 작업을 제출할 준비가 된 것입니다.</p><p><strong>1단계: 저장소 및 브랜치 선택</strong></p><p><a href="https://claude.ai/code" target="_blank" rel="noreferrer">claude.ai/code</a> 또는 Claude 모바일 앱의 Code 탭에서 입력 상자 아래의 저장소 선택기를 클릭하고 Claude가 작업할 저장소를 선택하세요. 각 저장소에는 브랜치 선택기가 표시됩니다. 기본값 대신 기능 브랜치에서 Claude를 시작하려면 변경하세요. 하나의 세션에서 여러 저장소에 걸쳐 작업하려면 저장소를 여러 개 추가할 수 있습니다.</p><p><strong>2단계: 권한 모드 선택</strong></p><p>입력 옆의 모드 드롭다운은 기본적으로 <strong>Auto accept edits</strong>로 설정되어 있으며, Claude가 승인 없이 변경 사항을 만들고 브랜치를 푸시합니다. 파일 수정 전에 Claude가 접근 방식을 제안하고 확인을 기다리도록 하려면 <strong>Plan mode</strong>로 전환하세요. 클라우드 세션은 Ask 권한, Auto 모드, Bypass 권한을 제공하지 않습니다. 전체 목록은 <a href="/claude-code-docs-ko/permission-modes.html">권한 모드</a>를 참조하세요.</p><p><strong>3단계: 작업 설명 및 제출</strong></p><p>원하는 내용을 입력하고 Enter를 누르세요. 구체적으로 작성하세요:</p><ul><li>파일이나 함수 이름을 명시하세요: &quot;설정 지침이 포함된 README 추가&quot; 또는 &quot;<code>tests/test_auth.py</code>의 실패하는 인증 테스트 수정&quot;이 &quot;테스트 수정&quot;보다 낫습니다.</li><li>오류 출력이 있다면 붙여넣으세요.</li><li>증상만이 아닌 예상 동작을 설명하세요.</li></ul><p>Claude가 저장소를 클론하고, 설정 스크립트가 있으면 실행한 뒤 작업을 시작합니다. 각 작업은 별도의 세션과 브랜치를 갖으므로, 하나가 완료될 때까지 기다리지 않고 다른 작업을 시작할 수 있습니다.</p><h2 id="검토-및-반복" tabindex="-1">검토 및 반복 <a class="header-anchor" href="#검토-및-반복" aria-label="Permalink to &quot;검토 및 반복&quot;">​</a></h2><p>Claude가 완료되면 변경 사항을 검토하고, 특정 라인에 피드백을 남기고, diff가 올바르게 보일 때까지 계속 진행하세요.</p><p><strong>1단계: diff 뷰 열기</strong></p><p>diff 표시기에는 세션 전체에서 추가 및 삭제된 라인이 표시됩니다(예: <code>+42 -18</code>). 이를 선택하면 왼쪽에 파일 목록이, 오른쪽에 변경 사항이 있는 diff 뷰가 열립니다.</p><p><strong>2단계: 인라인 댓글 남기기</strong></p><p>diff에서 라인을 선택하고, 피드백을 입력한 뒤 Enter를 누르세요. 댓글은 다음 메시지를 보낼 때까지 대기했다가 함께 전달됩니다. Claude는 메인 지시사항과 함께 &quot;<code>src/auth.ts:47</code>에서 오류를 여기서 잡지 마세요&quot;라는 내용을 보게 되므로, 문제의 위치를 별도로 설명할 필요가 없습니다.</p><p><strong>3단계: 풀 리퀘스트 생성</strong></p><p>diff가 올바르게 보이면 diff 뷰 상단의 <strong>Create PR</strong>을 선택하세요. 전체 PR, 드래프트로 열거나, 생성된 제목과 설명이 포함된 GitHub 작성 페이지로 이동할 수 있습니다.</p><p><strong>4단계: PR 이후에도 반복</strong></p><p>세션은 PR이 생성된 후에도 활성 상태를 유지합니다. CI 실패 출력이나 리뷰어 댓글을 채팅에 붙여넣고 Claude에게 처리를 요청하세요. Claude가 PR을 자동으로 모니터링하도록 하려면 <a href="/claude-code-docs-ko/claude-code-on-the-web.html#auto-fix-pull-requests">Auto-fix pull requests</a>를 참조하세요.</p><h2 id="설정-문제-해결" tabindex="-1">설정 문제 해결 <a class="header-anchor" href="#설정-문제-해결" aria-label="Permalink to &quot;설정 문제 해결&quot;">​</a></h2><h3 id="github-연결-후-저장소가-표시되지-않는-경우" tabindex="-1">GitHub 연결 후 저장소가 표시되지 않는 경우 <a class="header-anchor" href="#github-연결-후-저장소가-표시되지-않는-경우" aria-label="Permalink to &quot;GitHub 연결 후 저장소가 표시되지 않는 경우&quot;">​</a></h3><p>Claude GitHub App은 사용하려는 각 저장소에 대해 명시적인 접근 권한이 필요합니다. github.com에서 <strong>Settings → Applications → Claude → Configure</strong>를 열고 <strong>Repository access</strong> 아래에 저장소가 나열되어 있는지 확인하세요. 비공개 저장소도 공개 저장소와 동일한 인증이 필요합니다.</p><h3 id="페이지에-github-로그인-버튼만-표시되는-경우" tabindex="-1">페이지에 GitHub 로그인 버튼만 표시되는 경우 <a class="header-anchor" href="#페이지에-github-로그인-버튼만-표시되는-경우" aria-label="Permalink to &quot;페이지에 GitHub 로그인 버튼만 표시되는 경우&quot;">​</a></h3><p>클라우드 세션에는 연결된 GitHub 계정이 필요합니다. 위의 브라우저 흐름으로 연결하거나, GitHub CLI를 사용한다면 터미널에서 <code>/web-setup</code>을 실행하세요. GitHub 연결을 원하지 않는다면 <a href="/claude-code-docs-ko/remote-control.html">Remote Control</a>을 참조하여 Claude Code를 자신의 머신에서 실행하고 웹에서 모니터링하세요.</p><h3 id="not-available-for-the-selected-organization" tabindex="-1">&quot;Not available for the selected organization&quot; <a class="header-anchor" href="#not-available-for-the-selected-organization" aria-label="Permalink to &quot;&quot;Not available for the selected organization&quot;&quot;">​</a></h3><p>Enterprise 조직은 관리자가 웹에서의 Claude Code를 활성화해야 할 수 있습니다. Anthropic 계정 팀에 문의하세요.</p><h3 id="web-setup이-unknown-command-를-반환하는-경우" tabindex="-1"><code>/web-setup</code>이 &quot;Unknown command&quot;를 반환하는 경우 <a class="header-anchor" href="#web-setup이-unknown-command-를-반환하는-경우" aria-label="Permalink to &quot;`/web-setup`이 &quot;Unknown command&quot;를 반환하는 경우&quot;">​</a></h3><p><code>/web-setup</code>은 셸이 아닌 Claude Code CLI 내에서 실행합니다. 먼저 <code>claude</code>를 실행한 다음 프롬프트에서 <code>/web-setup</code>을 입력하세요.</p><p>Claude Code 내에서 입력했는데도 오류가 표시된다면, CLI가 v2.1.80보다 오래되었거나 claude.ai 구독 대신 API 키 또는 서드파티 공급자로 인증된 것입니다. <code>claude update</code>를 실행한 후 <code>/login</code>으로 claude.ai 계정에 로그인하세요.</p><h3 id="remote-또는-ultraplan-사용-시-could-not-create-a-cloud-environment-또는-no-cloud-environment-available" tabindex="-1"><code>--remote</code> 또는 ultraplan 사용 시 &quot;Could not create a cloud environment&quot; 또는 &quot;No cloud environment available&quot; <a class="header-anchor" href="#remote-또는-ultraplan-사용-시-could-not-create-a-cloud-environment-또는-no-cloud-environment-available" aria-label="Permalink to &quot;`--remote` 또는 ultraplan 사용 시 &quot;Could not create a cloud environment&quot; 또는 &quot;No cloud environment available&quot;&quot;">​</a></h3><p>원격 세션 기능은 환경이 없는 경우 기본 클라우드 환경을 자동으로 생성합니다. &quot;Could not create a cloud environment&quot;가 표시되면 자동 생성에 실패한 것입니다. &quot;No cloud environment available&quot;이 표시되면 CLI가 자동 생성 이전 버전입니다. 어느 경우든 Claude Code CLI에서 <code>/web-setup</code>을 실행하여 수동으로 생성하거나, <a href="https://claude.ai/code" target="_blank" rel="noreferrer">claude.ai/code</a>를 방문하여 위의 <strong>환경 생성</strong> 단계를 따르세요.</p><h3 id="설정-스크립트-실패" tabindex="-1">설정 스크립트 실패 <a class="header-anchor" href="#설정-스크립트-실패" aria-label="Permalink to &quot;설정 스크립트 실패&quot;">​</a></h3><p>설정 스크립트가 0이 아닌 상태 코드로 종료되어 세션 시작이 차단됩니다. 일반적인 원인:</p><ul><li>레지스트리가 <a href="/claude-code-docs-ko/claude-code-on-the-web.html#access-levels">네트워크 액세스 수준</a>에 포함되지 않아 패키지 설치에 실패한 경우. <code>Trusted</code>는 대부분의 패키지 관리자를 지원하며, <code>None</code>은 모두 차단합니다.</li><li>스크립트가 새 클론에 존재하지 않는 파일 또는 경로를 참조하는 경우.</li><li>로컬에서 작동하는 명령이 Ubuntu에서는 다른 방식으로 호출해야 하는 경우.</li></ul><p>디버깅하려면 스크립트 상단에 <code>set -x</code>를 추가하여 실패한 명령을 확인하세요. 중요하지 않은 명령에는 <code>|| true</code>를 추가하여 세션 시작을 차단하지 않도록 하세요.</p><h3 id="탭을-닫아도-세션이-계속-실행되는-경우" tabindex="-1">탭을 닫아도 세션이 계속 실행되는 경우 <a class="header-anchor" href="#탭을-닫아도-세션이-계속-실행되는-경우" aria-label="Permalink to &quot;탭을 닫아도 세션이 계속 실행되는 경우&quot;">​</a></h3><p>이것은 의도된 동작입니다. 탭을 닫거나 다른 페이지로 이동해도 세션이 중지되지 않습니다. Claude가 현재 작업을 완료할 때까지 백그라운드에서 계속 실행된 후 유휴 상태가 됩니다. 사이드바에서 세션을 <a href="/claude-code-docs-ko/claude-code-on-the-web.html#archive-sessions">아카이브</a>하여 목록에서 숨기거나, <a href="/claude-code-docs-ko/claude-code-on-the-web.html#delete-sessions">삭제</a>하여 영구적으로 제거할 수 있습니다.</p><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>이제 작업 제출 및 검토가 가능합니다. 다음 페이지에서는 터미널에서 클라우드 세션 시작, 반복 작업 예약, Claude에게 지속적인 지시 사항 제공 방법을 다룹니다.</p><ul><li><a href="/claude-code-docs-ko/claude-code-on-the-web.html">웹에서 Claude Code 사용</a>: 터미널로 세션 전환, 설정 스크립트, 환경 변수, 네트워크 설정 등 전체 레퍼런스</li><li><a href="/claude-code-docs-ko/web-scheduled-tasks.html">웹에서 작업 예약</a>: 일별 PR 검토, 의존성 감사 등 반복 작업 자동화</li><li><a href="/claude-code-docs-ko/memory.html">CLAUDE.md</a>: 모든 세션 시작 시 로드되는 Claude의 지속적인 지시 사항 및 컨텍스트 제공</li><li>Claude 모바일 앱을 설치하여 휴대폰에서 세션 모니터링: <a href="https://apps.apple.com/us/app/claude-by-anthropic/id6473753684" target="_blank" rel="noreferrer">iOS</a> 또는 <a href="https://play.google.com/store/apps/details?id=com.anthropic.claude" target="_blank" rel="noreferrer">Android</a>. Claude Code CLI에서 <code>/mobile</code>을 실행하면 QR 코드가 표시됩니다.</li></ul>',80)])])}const g=t(d,[["render",r]]);export{p as __pageData,g as default};
